class Solution:
    def numberOfPairs(self, points):
        n = len(points)
        count = 0
        for i in range(n):
            ax, ay = points[i]
            for j in range(n):
                if i == j: continue
                bx, by = points[j]
                # Alice upper-left, Bob lower-right
                if ax > bx or ay < by:
                    continue
                # Check no other point inside or on boundary
                ok = True
                for m in range(n):
                    if m == i or m == j: continue
                    px, py = points[m]
                    if ax <= px <= bx and by <= py <= ay:
                        ok = False
                        break
                if ok:
                    count += 1
        return count

solutions.python:
class Solution:
    def numberOfPairs(self, points):
        points.sort(key=lambda p: (p[0], -p[1]))
        n = len(points)
        count = 0
        for i in range(n):
            ax, ay = points[i]
            max_y = float('-inf')
            for j in range(i+1, n):
                bx, by = points[j]
                if by > ay:
                    continue
                if by > max_y:
                    count += 1
                    max_y = by
        return count

