var numberOfPairs = function(points) {
    points.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : b[1] - a[1]);
    const n = points.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        const [ax, ay] = points[i];
        let maxY = -Infinity;
        for (let j = i+1; j < n; j++) {
            const [bx, by] = points[j];
            if (by > ay) continue;
            if (by > maxY) {
                count++;
                maxY = by;
            }
        }
    }
    return count;
};
